68	async function mockGraphQL(page: import('@playwright/test').Page) {
69		await page.route('/graphql', async (route) => {
70			const body = route.request().postDataJSON() as { query: string };
71	
72			if (body.query.includes('NodeInfo')) {
73				await route.fulfill({
74					status: 200,
75					contentType: 'application/json',
76					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
77				});
78			} else if (body.query.includes('Projects')) {
79				await route.fulfill({
80					status: 200,
81					contentType: 'application/json',
82					body: JSON.stringify({
83						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
84					})
85				});
86			} else if (body.query.includes('BeadsByProject')) {
87				await route.fulfill({
88					status: 200,
89					contentType: 'application/json',
90					body: JSON.stringify({ data: makeBeadsResponse() })
91				});
92			} else if (body.query.includes('query Bead(')) {
93				await route.fulfill({
94					status: 200,
95					contentType: 'application/json',
96					body: JSON.stringify({ data: { bead: BEAD_DETAIL } })
97				});
98			} else if (body.query.includes('BeadCreate') || body.query.includes('beadCreate')) {
99				await route.fulfill({
100					status: 200,
101					contentType: 'application/json',
102					body: JSON.stringify({ data: { beadCreate: CREATED_BEAD } })
103				});
104			} else if (body.query.includes('BeadLifecycle') || body.query.includes('beadLifecycle')) {
105				// Subscriptions over HTTP are not expected; pass through
106				await route.continue();
107			} else {
108				await route.continue();
109			}
110		});
111	}
